**Custom Hook: `useNotification`**
```typescript
// @/src/hooks/useNotification.hooks.ts
import { createContext, useContext, useState, useEffect } from 'react';
import { NotificationContext } from '@/src/contexts/Nofitication.context';

interface NotificationProps {
  heading: string;
  subheading: string;
  type: string;
}

const useNotification = () => {
  const notificationElem = useContext(NotificationContext);
  const [error, setError] = useState(null);

  const notify = async (props: NotificationProps) => {
    if (!notificationElem) {
      setError('Notification element not found');
      return;
    }

    try {
      await notificationElem.open({
        heading: props.heading,
        subheading: props.subheading,
        type: props.type,
      });
    } catch (error) {
      setError(error.message);
    }
  };

  useEffect(() => {
    if (error) {
      console.error(error);
    }
  }, [error]);

  return { notify, error };
};

export default useNotification;
```
